// App.jsx
import { Routes, Route, Navigate } from "react-router-dom";
import { useState } from "react";

// Halaman Auth
import Register from "./pages/Auth/Register";
import Login from "./pages/Auth/Login";

// Halaman Dashboard
import Dashboard from "./pages/Dashboard/Dashboard";

// Halaman MasterData dan Tracking
import MasterData from "./pages/MasterData/MasterData";
import Tracking from "./pages/Tracking/Tracking";
import TrackingSuperAdmin from "./pages/Tracking/TrackingSuperAdmin";

// Halaman InfoDriver, ByPass, Settings
import InfoDriver from "./pages/Auth/InfoDriver";
import InfoDriverDetail from "./pages/Auth/InfoDriverDetail";
import ByPass from "./pages/Auth/ByPass";
import Settings from "./pages/Auth/Settings";

// Halaman EditTruck
import EditTruck from "./pages/MasterData/EditTruck";

// Halaman Checkpoint
import Checkpoint from "./pages/Dashboard/Checkpoint";

// Halaman Timbang Muat (✅ Tambahan Baru)
import TimbangMuat from "./pages/Dashboard/TimbangMuat";

import InputTGudang from "./pages/Dashboard/InputTGudang"; // ✅ Tambahan Baru

export default function App() {
  const [userRole, setUserRole] = useState(null);
  const isLoggedIn = !!userRole;

  const protectedRoute = (element, allowedRoles) => {
    if (!isLoggedIn) return <Navigate to="/login" />;
    if (!allowedRoles.includes(userRole)) return <Navigate to="/dashboard" />;
    return element;
  };

  return (
    <Routes>
      {/* Rute untuk Registrasi dan Login */}
      <Route path="/register" element={<Register />} />
      <Route path="/login" element={<Login setUserRole={setUserRole} />} />

      {/* Rute untuk Dashboard */}
      <Route
        path="/dashboard"
        element={
          isLoggedIn ? <Dashboard role={userRole} /> : <Navigate to="/login" />
        }
      />

      {/* Rute untuk halaman Master Data */}
      <Route
        path="/master-data"
        element={protectedRoute(<MasterData role={userRole} />, ["Admin"])}
      />

      {/* Rute untuk halaman Edit Truck */}
      <Route
        path="/edit-truck/:truckId"
        element={protectedRoute(<EditTruck role={userRole} />, ["Admin"])}
      />

      {/* Rute untuk halaman Tracking */}
      <Route
        path="/tracking"
        element={protectedRoute(
          userRole === "Super Admin" ? (
            <TrackingSuperAdmin role={userRole} />
          ) : (
            <Tracking role={userRole} />
          ),
          ["Admin", "Super Admin"]
        )}
      />

      {/* Rute untuk halaman Checkpoint */}
      <Route
        path="/checkpoint"
        element={protectedRoute(<Checkpoint role={userRole} />, ["Admin", "Super Admin"])}
      />

      {/* ✅ Rute baru untuk Timbang Muat */}
      <Route
        path="/timbang-muat"
        element={protectedRoute(<TimbangMuat role={userRole} />, ["Admin", "Super Admin"])}
      />

      <Route
        path="/input-tgudang"
        element={protectedRoute(<InputTGudang role={userRole} />, ["Admin", "Super Admin"])}
      />


      {/* Rute untuk halaman Info Driver */}
      <Route
        path="/info-driver"
        element={protectedRoute(<InfoDriver role={userRole} />, ["Admin", "Super Admin"])}
      />
      <Route
        path="/info-driver/:truckId"
        element={protectedRoute(<InfoDriverDetail role={userRole} />, ["Admin", "Super Admin"])}
      />

      {/* Rute untuk halaman lainnya */}
      <Route
        path="/bypass"
        element={protectedRoute(<ByPass role={userRole} />, ["Super Admin"])}
      />
      <Route
        path="/settings"
        element={protectedRoute(<Settings role={userRole} />, ["Admin", "Super Admin"])}
      />

      {/* Fallback jika rute tidak ditemukan */}
      <Route path="*" element={<Navigate to="/login" />} />
    </Routes>
  );
}
